  `authorized_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `remarks` TEXT DEFAULT NULL,
  `certificate_number` VARCHAR(50) DEFAULT NULL COMMENT 'e.g. BFP-FSIC-2025-000001',
  PRIMARY KEY (`id`),
  KEY `fk_certificates_inspection` (`inspection_id`),
  KEY `fk_certificates_establishment` (`establishment_id`),
  KEY `fk_certificates_authorized_by` (`authorized_by`),
  CONSTRAINT `fk_certificates_inspection` FOREIGN KEY (`inspection_id`) REFERENCES `inspection` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_certificates_establishment` FOREIGN KEY (`establishment_id`) REFERENCES `establishment` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_certificates_authorized_by` FOREIGN KEY (`authorized_by`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

